NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
const string s="mooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooo";
int a[30],n;
int f(int n)
{
	int x=3,i=0;
	wh(x<n)
	{
		i+=1;
		x=x+i+3+x;
		a[i]=x-1;
	}
	return i;
}
char d(int n,int w)
{
	if(n==0)return s[w];
	if(w<=a[n-1])return d(n-1,w);
	if(w<=a[n-1]+n+3)return s[w-a[n-1]-1];
	return d(n-1,w-(a[n-1]+n+3)-1);
}
signed main(void)
{
	a[0]=2,cin>>n;
	cout<<d(f(n),n-1);
    return false;
